import React, { useEffect, useState, useRef } from "react";
import {
  TrendingUp,
  Users,
  Activity,
  DollarSign,
  Package,
  Clock,
  RefreshCw,
  ShoppingBag,
  Zap,
  FileText,
  AlertTriangle,
  Plus,
  ArrowRight,
  ShieldCheck,
  BarChart3,
} from "lucide-react";
import { getSocket } from "../../socket";
import { Column, Pie } from "@ant-design/plots";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import {
  getOverviewKPIs,
  getSalesAnalytics,
  getInventoryAnalytics,
} from "../../features/b2b/b2bSlice";

const KPI_DATA = [
  {
    label: "Wholesale Revenue",
    icon: <DollarSign size={24} />,
    bgClass: "bg-teal-50",
    textClass: "text-teal-600",
    glowClass: "bg-teal-100",
    link: "/admin/b2b/orders",
  },
  {
    label: "Credit Orders",
    icon: <ShoppingBag size={24} />,
    bgClass: "bg-indigo-50",
    textClass: "text-indigo-600",
    glowClass: "bg-indigo-100",
    link: "/admin/b2b/orders",
  },
  {
    label: "Active Buyers",
    icon: <ShieldCheck size={24} />,
    bgClass: "bg-emerald-50",
    textClass: "text-emerald-600",
    glowClass: "bg-emerald-100",
    link: "/admin/b2b/customers",
  },
  {
    label: "Open RFQs",
    icon: <FileText size={24} />,
    bgClass: "bg-amber-50",
    textClass: "text-amber-600",
    glowClass: "bg-amber-100",
    link: "/admin/b2b/rfq",
  },
];

const B2bDashboard = () => {
  const dispatch = useDispatch();
  const [loading, setLoading] = useState(true);
  const [lastRefreshed, setLastRefreshed] = useState(new Date());
  const intervalRef = useRef(null);

  const fetchAllData = () => {
    setLoading(true);
    dispatch(getOverviewKPIs());
    dispatch(getSalesAnalytics("month"));
    dispatch(getInventoryAnalytics()).then(() => setLoading(false));
    setLastRefreshed(new Date());
  };

  useEffect(() => {
    fetchAllData();
    intervalRef.current = setInterval(() => {
      dispatch(getOverviewKPIs());
      dispatch(getSalesAnalytics("month"));
      dispatch(getInventoryAnalytics());
      setLastRefreshed(new Date());
    }, 60000);

    const socket = getSocket();
    const handleRefresh = () => fetchAllData();
    if (socket) socket.on("dashboard:refresh", handleRefresh);

    return () => {
      clearInterval(intervalRef.current);
      if (socket) socket.off("dashboard:refresh", handleRefresh);
    };
  }, [dispatch]);

  const { kpis, salesAnalytics, inventoryAnalytics } = useSelector(
    (state) => state.b2b
  );

  const kpiValues = [
    kpis?.sales?.totalRevenue?.toLocaleString() || "0",
    kpis?.sales?.creditOrders || "0",
    kpis?.customers?.verified || "0",
    kpis?.rfqs?.pending || "0",
  ];

  const kpiUnits = [
    "ETB",
    `Orders (${kpis?.sales?.creditRevenue?.toLocaleString()} ETB)`,
    `Verified (${kpis?.customers?.pendingVerification || 0} Pending)`,
    "Submissions",
  ];

  const salesTrendData =
    salesAnalytics?.salesTrend?.map((item) => ({
      period: new Date(item.timePeriod).toLocaleDateString("en-US", {
        month: "short",
        year: "2-digit",
      }),
      revenue: item.revenue,
    })) || [];

  const categoryInventoryData =
    inventoryAnalytics?.categoryInventory?.map((item) => ({
      category: item.category.replace(/_/g, " "),
      valuation: item.valuation,
    })) || [];

  const quickActions = [
    {
      title: "Add B2B Product",
      desc: "List wholesale / stock item",
      icon: <Plus size={22} />,
      bgClass: "bg-emerald-50",
      textClass: "text-emerald-600",
      to: "/admin/product",
    },
    {
      title: "Wholesale Products",
      desc: "Manage B2B catalog",
      icon: <Package size={22} />,
      bgClass: "bg-teal-50",
      textClass: "text-teal-600",
      to: "/admin/b2b/products",
    },
    {
      title: "Wholesale Orders",
      desc: "Approve & track orders",
      icon: <ShoppingBag size={22} />,
      bgClass: "bg-indigo-50",
      textClass: "text-indigo-600",
      to: "/admin/b2b/orders",
    },
  ];

  return (
    <div className="dashboard-wrapper">
      {/* ── Hero Header Section ── */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
        <div className="space-y-1">
          <div className="flex items-center gap-2 mb-2">
            <div className="h-1 w-8 bg-teal-500 rounded-full" />
            <span className="text-[11px] font-black text-teal-600 uppercase tracking-[0.2em]">
              B2B Wholesale Console
            </span>
          </div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">
            Procurement<span className="text-teal-500">.</span>
          </h1>
          <p className="text-[15px] text-slate-400 font-bold">
            Hospital procurement cycles, wholesale billing, and inventory tracking.
          </p>
        </div>

        <div className="flex items-center gap-4">
          <div className="bg-white p-2 rounded-2xl border border-slate-100 flex items-center gap-4 shadow-sm">
            <div className="flex items-center gap-2 px-3 py-1.5 bg-teal-50 text-teal-600 rounded-xl text-[12px] font-black border border-teal-100/50">
              <div className="w-2 h-2 rounded-full bg-teal-500 animate-pulse" />
              WHOLESALE PORTAL
            </div>
            <button
              onClick={fetchAllData}
              disabled={loading}
              className="p-2 text-slate-400 hover:text-teal-600 transition-colors"
            >
              <RefreshCw size={20} className={loading ? "animate-spin" : ""} />
            </button>
          </div>
        </div>
      </div>

      {/* ── Smart KPI Grid ── */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-10">
        {KPI_DATA.map((k, i) => (
          <Link
            to={k.link}
            className="b2b-kpi-card relative group overflow-hidden block"
            key={i}
          >
            <div className="flex justify-between items-start relative z-10">
              <div
                className={`w-12 h-12 rounded-2xl flex items-center justify-center ${k.bgClass} ${k.textClass} group-hover:scale-110 transition-transform duration-500`}
              >
                {k.icon}
              </div>
              <span className="text-[10px] font-black text-teal-400 uppercase tracking-widest flex items-center gap-1 group-hover:gap-2 transition-all">
                View <ArrowRight size={12} />
              </span>
            </div>
            <div className="mt-6 relative z-10">
              <p className="text-[12px] font-black text-slate-400 uppercase tracking-widest mb-1">
                {k.label}
              </p>
              <div className="flex flex-col items-start gap-1">
                <span className="text-3xl font-black text-slate-900 tracking-tight">
                  {loading ? "..." : kpiValues[i]}
                </span>
                <span className="text-[11px] font-bold text-slate-400 uppercase tracking-tight">
                  {kpiUnits[i]}
                </span>
              </div>
            </div>
            {/* Background Glow */}
            <div
              className={`absolute -right-4 -bottom-4 w-28 h-28 ${k.glowClass} rounded-full blur-2xl opacity-0 group-hover:opacity-100 transition-opacity duration-500`}
            />
          </Link>
        ))}
      </div>

      {/* ── Quick Actions ── */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-10">
        {quickActions.map((action, i) => (
          <Link
            key={i}
            to={action.to}
            className="b2b-enterprise-card bg-white border border-slate-100 rounded-2xl p-5 flex items-center gap-4 group hover:border-teal-100"
          >
            <div
              className={`w-12 h-12 rounded-2xl ${action.bgClass} ${action.textClass} flex items-center justify-center group-hover:scale-110 transition-transform duration-300`}
            >
              {action.icon}
            </div>
            <div className="flex-1">
              <p className="font-black text-slate-900 text-sm">{action.title}</p>
              <p className="text-xs text-slate-400 font-bold">{action.desc}</p>
            </div>
            <ArrowRight size={16} className="text-slate-300 group-hover:text-teal-500 group-hover:translate-x-1 transition-all" />
          </Link>
        ))}
      </div>

      {/* ── Critical Stock Alerts Bar ── */}
      {(kpis?.inventory?.outOfStock > 0 ||
        kpis?.inventory?.lowStock > 0 ||
        kpis?.inventory?.expiringSoon > 0) && (
        <div className="bg-gradient-to-r from-rose-50 to-rose-50/50 border border-rose-100 rounded-3xl p-6 mb-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-2xl bg-rose-500 text-white flex items-center justify-center shrink-0 shadow-lg shadow-rose-200">
              <AlertTriangle size={24} />
            </div>
            <div>
              <h3 className="font-black text-rose-900 text-lg leading-tight">
                Immediate Inventory Attention Required
              </h3>
              <p className="text-rose-600 text-sm font-bold mt-1">
                Stock metrics have crossed critical thresholds. Check expiring soon and low-stock items.
              </p>
            </div>
          </div>
          <div className="flex gap-4 shrink-0 flex-wrap">
            <div className="bg-white px-4 py-2.5 rounded-2xl border border-rose-200 text-center min-w-[90px] shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Out of Stock</p>
              <p className="text-xl font-black text-rose-600">{kpis?.inventory?.outOfStock}</p>
            </div>
            <div className="bg-white px-4 py-2.5 rounded-2xl border border-rose-200 text-center min-w-[90px] shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Low Stock</p>
              <p className="text-xl font-black text-amber-500">{kpis?.inventory?.lowStock}</p>
            </div>
            <div className="bg-white px-4 py-2.5 rounded-2xl border border-rose-200 text-center min-w-[90px] shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Expiring (90d)</p>
              <p className="text-xl font-black text-rose-500">{kpis?.inventory?.expiringSoon}</p>
            </div>
            <Link
              to="/admin/b2b/inventory"
              className="b2b-btn-danger flex items-center"
            >
              <AlertTriangle size={16} />
              Resolve Alerts
            </Link>
          </div>
        </div>
      )}

      {/* ── Main Insights Area ── */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8 mb-10">
        {/* Revenue Chart */}
        <div className="xl:col-span-2 b2b-enterprise-card bg-white border border-slate-100 p-8">
          <div className="flex justify-between items-center mb-10">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-teal-50 text-teal-600 flex items-center justify-center">
                <TrendingUp size={20} />
              </div>
              <div>
                <h3 className="text-[18px] font-black text-slate-900">Wholesale Revenue Trend</h3>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Monthly Performance</p>
              </div>
            </div>
          </div>
          <div className="h-[340px] px-2">
            {salesTrendData.length > 0 ? (
              <Column
                data={salesTrendData}
                xField="period"
                yField="revenue"
                color="#14b8a6"
                padding="auto"
                columnStyle={{ radius: [10, 10, 0, 0] }}
                xAxis={{
                  label: { style: { fill: "#64748b", fontSize: 11, fontWeight: 700 } },
                }}
                yAxis={{
                  label: { style: { fill: "#64748b", fontSize: 11, fontWeight: 700 } },
                }}
              />
            ) : (
              <div className="h-full flex flex-col items-center justify-center opacity-30">
                <Activity size={48} className="text-slate-200 mb-4" />
                <p className="text-sm font-black uppercase tracking-widest">
                  No Sales Data Recorded
                </p>
              </div>
            )}
          </div>
        </div>

        {/* Category Split */}
        <div className="b2b-enterprise-card bg-white border border-slate-100 p-8">
          <div className="flex justify-between items-center mb-8">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-slate-50 text-slate-600 flex items-center justify-center">
                <BarChart3 size={20} />
              </div>
              <div>
                <h3 className="text-[18px] font-black text-slate-900">Category Split</h3>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Stock Valuation</p>
              </div>
            </div>
          </div>
          <div className="h-[340px] relative">
            {categoryInventoryData.length > 0 ? (
              <Pie
                data={categoryInventoryData}
                angleField="valuation"
                colorField="category"
                radius={0.8}
                innerRadius={0.6}
                padding="auto"
                legend={{
                  position: "bottom",
                  layout: "vertical",
                }}
                color={["#14b8a6", "#0d9488", "#0f766e", "#134e4a", "#115e59", "#99f6e4", "#5eead4", "#2dd4bf", "#14b8a6", "#0d9488"]}
                label={{
                  type: "inner",
                  offset: "-50%",
                  content: "{value}",
                  style: {
                    textAlign: "center",
                    fontSize: 10,
                    fontWeight: 700,
                  },
                }}
              />
            ) : (
              <div className="h-full flex flex-col items-center justify-center opacity-30">
                <Activity size={48} className="text-slate-200 mb-4" />
                <p className="text-sm font-black uppercase tracking-widest">
                  No Inventory Valued
                </p>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* ── System Footer ── */}
      <div className="flex flex-col sm:flex-row items-center justify-between gap-6 border-t border-slate-100 pt-10 pb-6 opacity-60">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-teal-500 to-teal-700 flex items-center justify-center text-white">
            <Zap size={14} fill="white" strokeWidth={0} />
          </div>
          <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">
            Pulse Addis B2B OS v2.0
          </p>
        </div>
        <div className="flex items-center gap-6">
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Last refreshed: {lastRefreshed.toLocaleTimeString()}</span>
        </div>
      </div>
    </div>
  );
};

export default B2bDashboard;
